document.addEventListener("DOMContentLoaded",function(){var e=document.getElementById("timestampdiv"),t=document.getElementById("timestamp"),n=t.innerHTML,a=t.nextElementSibling,l=a.querySelector("summary"),m=e.querySelector(".timestamp-wrap"),d=document.getElementById("mm"),u=document.getElementById("jj"),c=document.getElementById("aa"),i=document.getElementById("hh"),o=document.getElementById("mn");e.querySelector(".cancel-timestamp").addEventListener("click",function(e){a.removeAttribute("open"),l.focus(),d.value=document.getElementById("hidden_mm").value,u.value=document.getElementById("hidden_jj").value,c.value=document.getElementById("hidden_aa").value,i.value=document.getElementById("hidden_hh").value,o.value=document.getElementById("hidden_mn").value,t.innerHTML=n,e.preventDefault()}),e.querySelector(".save-timestamp").addEventListener("click",function(e){var n=c.value,r=d.value,s=u.value,v=i.value,p=o.value,y=new Date(n,r-1,s,v,p);e.preventDefault(),y.getFullYear()==n&&1+y.getMonth()==r&&y.getDate()==s&&y.getMinutes()==p?(m.classList.remove("form-invalid"),t.innerHTML=wp.i18n.__("Submitted on:")+" <b>"+wp.i18n.__("%1$s %2$s, %3$s at %4$s:%5$s").replace("%1$s",document.querySelector('option[value="'+r+'"]',"#mm").dataset.text).replace("%2$s",parseInt(s,10)).replace("%3$s",n).replace("%4$s",("00"+v).slice(-2)).replace("%5$s",("00"+p).slice(-2))+"</b> ",a.removeAttribute("open"),l.focus()):m.classList.add("form-invalid")})});